return {
  dataType: 'mlb',
  dateInfo: {
    today: 'Monday, August 26, 2024',
    theme: 'Humility & Simplicity',
    dayOfWeek: 'Monday'
  },
  game: {
    score: 'LAD 8, Cincinnati Reds 4',
    gameUrl: 'https://www.mlb.com/dodgers'
  },
  standings: {
    wins: 85,
    losses: 58
  },
  fullRecord: '85-58',
  standingSummary: '1st in NL West'
};

// Test Email Compiler - Process merged data using combine mode
const items = $input.all();
console.log('Received items count:', items.length);

// In combine mode, we get all items from all inputs
let aiData = null;
let mlbData = null;

for (const item of items) {
  const data = item.json;
  console.log('Processing item:', JSON.stringify(data, null, 2));

  if (data.dataType === 'ai' || data.text) {
    aiData = data;
    console.log('Found AI data');
  } else if (data.dataType === 'mlb') {
    mlbData = data;
    console.log('Found MLB data');
  }
}

// Create fallback data if needed
if (!mlbData) {
  console.log('No MLB data found, using fallback');
  mlbData = {
    dateInfo: { today: 'Test Day', theme: 'Test Theme' },
    game: { score: 'No game data' },
    standings: { wins: 0, losses: 0 },
    fullRecord: '0-0'
  };
}

if (!aiData) {
  console.log('No AI data found, using fallback');
  aiData = { text: '{"reflection": "Fallback reflection"}', dataType: 'ai' };
}

// Parse AI content
let spiritual = {};
try {
  const aiText = aiData.text || '{}';
  spiritual = JSON.parse(aiText);
  console.log('Parsed AI content successfully');
} catch (e) {
  console.log('Error parsing AI content:', e.message);
  spiritual = { reflection: 'Fallback spiritual content' };
}

// Create simple test output
const result = {
  success: true,
  message: 'Combine merge successful',
  mode: 'combine',
  totalItems: items.length,
  data: {
    aiDataFound: !!aiData,
    mlbDataFound: !!mlbData,
    spiritualReflection: spiritual.reflection || 'No reflection',
    gameScore: mlbData.game?.score || 'No game score',
    todaysDate: mlbData.dateInfo?.today || 'No date'
  }
};

console.log('Final result:', JSON.stringify(result, null, 2));

return result;
